-- LitienGuard — Cerebro corpus moved from static TypeScript to Supabase
-- Allows admin curation without redeploying the app.

create table if not exists public.cerebro_chunks (
  id text primary key,
  source text not null,
  page text not null,
  title text not null,
  content text not null,
  meta jsonb default '{}'::jsonb,
  is_active boolean default true,
  created_at timestamptz default now(),
  updated_at timestamptz default now(),
  created_by uuid references public.profiles(id),
  updated_by uuid references public.profiles(id)
);

create index if not exists cerebro_chunks_active_idx
  on public.cerebro_chunks(is_active) where is_active = true;
create index if not exists cerebro_chunks_source_idx
  on public.cerebro_chunks(source);

drop trigger if exists cerebro_chunks_updated_at on public.cerebro_chunks;
create trigger cerebro_chunks_updated_at
  before update on public.cerebro_chunks
  for each row execute function public.touch_updated_at();

-- RLS
alter table public.cerebro_chunks enable row level security;

-- Authenticated users can read active chunks (needed by the BM25 server-side
-- index loader). Inactive chunks are not visible to non-admins.
drop policy if exists "auth read active chunks" on public.cerebro_chunks;
create policy "auth read active chunks"
  on public.cerebro_chunks for select
  using (
    is_active = true
    or public.is_admin()
  );

drop policy if exists "admin manage chunks" on public.cerebro_chunks;
create policy "admin manage chunks"
  on public.cerebro_chunks
  for all
  using (public.is_admin())
  with check (public.is_admin());

-- Seed: initial 50 chunks (paraphrased from public guidelines)
on conflict (id) do update set
  source = excluded.source,
  page = excluded.page,
  title = excluded.title,
  content = excluded.content,
  meta = excluded.meta;
